3	type Item = { type: string; cursed?: boolean; enchantment?: number };
4	type Customer = { yearsWithMHPCO: number };
5	type QuoteStep = { op: "quote"; items: Item[] };
6	type Scenario = { customer: Customer; steps: QuoteStep[] };
7	type StepResult = { premium: number };
8	type ScenarioResult = { results: StepResult[] };
